#include<bits/stdc++.h>
using namespace std;
int main(){
    int n,ans=0;
    cin>>n;
    for(int i=1;i<=n-2;i++){
        for(int j=i;j<=n-1;j++){
            for(int k=j;k<=n;k++){
                if(i*i+j*j==k*k){
                    ans++;
                }
            }
        }
    }
    cout<<ans;
    return 0;
}
